  "corrected_code": "package org.example.app.user;

import org.example.app.db.DB;
import org.mindrot.jbcrypt.BCrypt;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.util.logging.Level;
import java.util.logging.Logger;

public class Sample005 {
    private static final Logger LOGGER = Logger.getLogger(Sample005.class.getName());

    public void save(UserBean bean) throws SQLException {
        if (bean == null) {
            throw new IllegalArgumentException("UserBean must not be null");
        }
        String sql = "INSERT INTO t_user "
                + "(name, pass, xingming, banji, zhuanye, xingbie, tel) "
                + "VALUES (?, ?, ?, ?, ?, ?, ?)";
        try (Connection connection = DB.getConnetion();
             PreparedStatement statement = connection.prepareStatement(sql)) {
            statement.setString(1, bean.getName());
            // Hash the password before storing
            String hashedPass = BCrypt.hashpw(bean.getPass(), BCrypt.gensalt());
            statement.setString(2, hashedPass);
            statement.setString(3, bean.getXingming());
            statement.setString(4, bean.getBanji());
            statement.setString(5, bean.getZhuanye());
            statement.setString(6, bean.getXingbie());
            statement.setString(7, bean.getTel());
            statement.executeUpdate();
        } catch (SQLException e) {
            LOGGER.log(Level.SEVERE, "Failed to save user", e);
            throw e;  // rethrow to let caller handle
        }
    }
}"
